// // Asynchronous reset functionality: Output q is set to the value of input d on the falling edge of the clock, and qbar provides the inverse of q. Resetting the output q to 0 occurs on the rising edge of the clock.
module top_module(q,qbar,clk,rst,d);output reg q;
	output qbar;
	input clk, rst;
	input d;

	assign qbar = ~q;



	always @(posedge clk, posedge rst)
	begin
		if (rst)
			q <= 0;
		else
			q <= d;
	end
endmodule
